ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  "status": "DOWN",
  "timestamp": now() as String,
  "services": {
    "oracle-billing": {
      "status": if (vars.oracleHealthy default false) "UP" else "DOWN",
      "lastChecked": now() as String
    },
    "outage-management": {
      "status": if (vars.outageHealthy default false) "UP" else "DOWN", 
      "lastChecked": now() as String
    },
    "analytics-service": {
      "status": if (vars.analyticsHealthy default false) "UP" else "DOWN",
      "lastChecked": now() as String
    },
    "agentforce": {
      "status": if (vars.agentforceHealthy default false) "UP" else "DOWN",
      "lastChecked": now() as String
    }
  },
  "version": "${app.version}",
  "environment": "${mule.env}"
}

%dw 2.0
output application/json
---
{
  customerId: vars.customerId,
  predictions: {
    nextMonthUsage: "unavailable",
    nextMonthCost: "unavailable",
    peakUsageDays: [],
    savingsOpportunities: []
  },
  insights: {
    message: "Advanced analytics are temporarily unavailable. Basic usage data is still accessible.",
    alternativeActions: [
      "View current usage data",
      "Check billing information", 
      "Get general energy saving tips"
    ]
  }
}

%dw 2.0
output application/json
---
{
  "message": "Outage information is temporarily unavailable. Please check our website or call customer service for current outage status.",
  "alternativeContacts": [
    {
      "method": "phone",
      "number": "1-800-UTILITY",
      "hours": "24/7"
    },
    {
      "method": "website", 
      "url": "https://www.utility.com/outages",
      "description": "Live outage map"
    }
  ]
}
